var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"이제 포기하십셔, 나쁜 아저씨!","JPN":"もう諦めるっす、悪いおじさん！","ENG":"Give up now, you evil man!","TWN":"壞叔叔，棄械投降吧！"},"stage":{"bg":"VILLAGE1","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"메이드장님이 가르쳐 주신 손빨래는 천하무적이지 말임다!","JPN":"メイド長が教えてくれた手洗いスキルは無敵っすよ！","ENG":"My laundry skills were taught by the Chief Maid herself!","TWN":"女僕長教我的手洗衣服可是天下無敵唷！"},"stage":{"bg":"VILLAGE1","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"큭……!","JPN":"くっ……！","ENG":"Pfft!","TWN":"咳…！"},"stage":{"bg":"VILLAGE1","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"그만두지 않겠다면 모네도 용서 안 할 검다!","JPN":"降参しないなら、モネも許さないっす！","ENG":"Stop right now, or Mone won’t forgive you!","TWN":"再不住手莫妮真的要生氣氣囉！"},"stage":{"bg":"VILLAGE1","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"아네모네─!","JPN":"アネモネ～！","ENG":"Anemone—","TWN":"必殺銀蓮花──！"},"stage":{"bg":"VILLAGE1","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"우왓!?","JPN":"うわっ！？","ENG":"Wah?!","TWN":"哇啊！？"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"모네 양, 일어설 수 있겠나?","JPN":"モネ、立てそうか？","ENG":"Mone, can you stand?","TWN":"莫妮，你站得起來嗎？"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"네, 넵! 주인님! 이 정도로는 끄떡없슴다!","JPN":"は、はいっ、ご主人様！　この程度は平気っす！","ENG":"Y-yes, sir! It’s nothing!","TWN":"是！主人！這點程度打不倒我的唷！"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_Q","text":{"KOREA":"캬하하하!","JPN":"キャハハハ！","ENG":"Kya hah hah!","TWN":"哇哈哈哈！"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_Q","text":{"KOREA":"뭐야, 기다리다 따분해서 와 봤더니 나 빼놓고 재밌는 거 하고 있었네?","JPN":"なーんだ、待つのが退屈すぎて来てみたら、あたし抜きで楽しそうにしてるじゃん？","ENG":"I got bored, so I came back, and I see that you’re all having fun without me!","TWN":"什麼嘛，我等到有點無聊想說來看一下，結果你們竟然幹壞事沒通知我？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_Q","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L19_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_Q","text":{"KOREA":"흐응, 저런 꼬맹이한테 탈탈 털린 거야?","JPN":"ふーん、あんなチビにボッコボコにされたの？","ENG":"Hmm, you guys got beaten up by a kid?","TWN":"呃嗯，連一個小鬼都擺不平？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_Q","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_Q","text":{"KOREA":"에휴. 나였으면 당장 용병질 관뒀겠다. 다 큰 사회인이 쪽팔리게시리.","JPN":"あたしだったら恥ずかしすぎて傭兵引退宣言するわ。みっともねえな。","ENG":"And you call yourselves mercenaries? Shame on you.","TWN":"哎唷，要是我就立刻辭掉傭兵職務回鄉下種田，這麼大的人不覺得丟臉嗎？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_Q","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"드라코! 어딜 어슬렁거리다 이제 기어 들어오는 거냐!","JPN":"ドラコ！　どこでのんびりしてたんだよ！","ENG":"Dracasia, where have you been? You’re late!","TWN":"德拉克！你去哪裡摸魚現在才回來！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_Q","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"아, 귀청 따가워. 깨졌으면 조용히 처박혀 있을 것이지.","JPN":"もお、うるさいな。負けたなら大人しく引っ込んでろよ。","ENG":"Stop screaming. Why don’t you get lost like the losers you are?","TWN":"哎唷，你好吵，打輸的人哪那麼多話。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"이…… 건방진 자식……!","JPN":"この……生意気な小娘が……！","ENG":"You... arrogant...","TWN":"這…傲慢的傢伙……!"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"뭐, 뭐임까? 같은 편이라 도와 준 거 아니었슴까?","JPN":"な、なんっすか？　味方だから助けたんじゃないっすか？","ENG":"W-what are you doing, ma’am? I thought you helped them because you were on the same side.","TWN":"這是怎樣？自己人起內鬨嗎？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"같은 편? 나 같은 초절 미소녀가 저런 땀내 나는 아재들이랑?","JPN":"味方？　あたしみたいな超絶美少女があんな汗臭いおっさんどもの味方？","ENG":"Me, a super pretty girl, on the same side as those sweaty old losers?","TWN":"自己人？我這種超級美少女和那些臭酸的大叔？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"절대 무리. 생리적으로 무리지. 인생이 불쌍해서 데리고 다녀 준다면 모를까.","JPN":"絶対無理。生理的に無理。可哀そうだしちょっと付き合うだけならいいけど。","ENG":"Never. Never-ever-ever. I only keep them around because they are so pathetic. I feel sorry for them.","TWN":"不可能，這輩子都不可能。說我是因為看他們可憐，才把他們帶在身邊的話，這樣還說得過去。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"아, 아무튼 얼른 데리고 가십셔! 앞으로 모네네 마을에서 난동 피우면 가만 안 있을 검다!","JPN":"と、とにかく早く全員連れて帰ってくださいっす！　またモネの村で暴れたら今度は容赦しないっす！","ENG":"O-okay, so take them with you, ma’am! And don’t you mess with Mone’s village ever again!","TWN":"總…總之，請快點把他們帶走！之後再到這裡搗亂的話，我就不客氣囉！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"싫은데?","JPN":"嫌なんだけど。","ENG":"Nope.","TWN":"才不要！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"엑?! 어째서임까!","JPN":"え！？　なぜっすか？","ENG":"Huh?! Why not?","TWN":"呃？！為什麼？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_COMIC_03"},{"id":"L32_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"난 이 생선 비린내 나는 마을을 싹 밀어 버려 달라고 리조트에 부탁 받은 몸이거든.","JPN":"あたしはこの魚の生臭さが充満する村を壊してほしいってリゾートに頼まれてきたわけ。","ENG":"The resort asked me to remove this fishy village from the face of the Earth.","TWN":"我是受度假村的委託，要剷平這個充滿魚腥味的村子。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"맘에 안 들면 어디 덤벼 보시든가?","JPN":"気に食わねえならかかってこいよ！","ENG":"If you don’t like it, you can just fight me.","TWN":"不想的話就放馬過來吧？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"아. 미리 말해 두는데 난 저 아저씨들처럼 쉽게 당해 주지 않을 거야.","JPN":"あ、先に言っとくけどあたしはあのおっさんたちと違って簡単にはやられねえよ。","ENG":"Oh, but beware, I won’t go down as easy as those old losers.","TWN":"不過我好心提醒你，我可不像那些大叔那麼好對付喔。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"프론트 베이의 드라코 선장님이라고 하면 모르는 녀석이 없단 말씀.","JPN":"フロントベイのドラコ船長といえば、名の知れた有名人なの。","ENG":"Everyone knows Dracasia the pirate captain from Front Bay.","TWN":"前灣的德拉克船長沒有人不知道。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"으으……! 그런 말도 안 되는 억지가 어딨슴까!","JPN":"むむ……！　村を壊すなんてそんな話、納得できないっす！","ENG":"Ugh... That’s ridiculous!","TWN":"呃呃…！哪有這麼野蠻的 !"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L39_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"기다리게, 모네 양.","JPN":"よせ、モネ。","ENG":"Wait, Mone.","TWN":"莫妮，先等一下。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L40_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"주, 주인님!","JPN":"ご、ご主人様！","ENG":"M-Master?","TWN":"主…主人！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L41_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"진정하게. 상대가 도발한다고 덤비면 오히려 당할 수도 있어.","JPN":"落ち着け。相手の挑発に容易に乗るとまんまとやられてしまうぞ。","ENG":"Stay calm. She’s only taunting you to get to you.","TWN":"冷靜點，不要落入對方的圈套，她這是激將法。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"하, 하지만 저 언니 좀 보십셔! 인상도 하는 말도 완전 못돼먹었슴다!","JPN":"で、でもあの人の話はあまりにもひどいっす！　顔つきも喋ってることも、悪党そのものっす！","ENG":"B-but look at her, sir! The way she looks and talks, she’s so mean!","TWN":"可…可是你看那個姊姊，長相和語氣都很糟糕！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"야, 그 로봇 뭐야? 좀 귀엽게 생겼다?","JPN":"ねえ、そのロボットはなに？　なかなか可愛いじゃない。","ENG":"Hey, what’s with the robot? It’s kinda cute.","TWN":"喂，那個機器人是什麼？看起來好可愛喔！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"……넵?","JPN":"はいっ……？","ENG":"... What?","TWN":"…什麼？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"이게?","JPN":"これが？","ENG":"This thing?","TWN":"你說這個東西？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>이게</color>라니…… 자네 평소에 내 걸작을 그런 눈으로 보고 있었나?","JPN":"<color=#ffd34c>これが</color>って……君、私の傑作を普段そんな目でみてたのか？","ENG":"“<color=#ffd34c>This thing</color>”? Is that what you actually think of my masterpiece?","TWN":"<color=#ffd34c>這個東西</color>…在你眼裡我是個東西嗎？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"야, 꼬맹이. 저 로봇이랑 셀카 한 번 찍게 해 주면 오늘은 얌전히 물러나 줄게.","JPN":"ねえ、チビ。あのロボットと1回だけ自撮りさせてくれたら今日は大人しく帰ってやるよ。","ENG":"Hey, kid. Let me take a selfie with that robot, and I’ll leave y’all alone for today.","TWN":"喂，小鬼！讓我和那個機器人拍一張自拍，那我今天就先乖乖離開。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"안 됨다! 주인님은 나쁜 사람 싫어하시지 말임다!","JPN":"ダメっす！　ご主人様は悪い人が嫌いなんっす！","ENG":"No, ma’am! Master hates bad people!","TWN":"不行唷！主人不喜歡壞人唷！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"뭐 어때. 사진 한 번 찍는 거 가지고.","JPN":"別にいいじゃない。写真一枚くらい。","ENG":"Don’t be so hard. It’s just a selfie.","TWN":"又沒關係，拍一張就好嘛！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"멈춰, 드라코!","JPN":"待て、ドラコ！","ENG":"Stop it, Dracasia!","TWN":"閉嘴，德拉克！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"제멋대로 굴지 마! 클라이언트와 약속한 기한이 코앞이라고!","JPN":"勝手なことするな！　クライアントと約束した期限が迫ってきてるぞ！","ENG":"You can’t make that call! The deadline for our contract is near!","TWN":"別胡鬧了！和客戶約定的期限就快到了！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"아, 진짜. 쫑알쫑알 시끄럽네. 어차피 아저씨네만으로는 가망 없으면서.","JPN":"んもーうるせえな。どうせおっさんたちだけじゃ無理だろ？","ENG":"Aw man, you’re a chatty one, aren’t you? You losers can’t do anything anyways.","TWN":"真是的，一直嘀嘀咕咕的。光靠大叔們又成不了大事。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"한참 어린 나 아니면 아무것도 못하는 주제에 잘난 척은. 바보 아냐?","JPN":"こんな幼いあたしがいないと何もできねえくせに、えらそうな口利くんじゃねえよ。バカじゃない？","ENG":"I’m far younger than you are, and you’re nothing without me. Are you worthless?","TWN":"明明就沒什麼用，還不是要靠我這個弱女子，有夠蠢的！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"크윽……!","JPN":"くうっ……！","ENG":"Ngh!","TWN":"咳呃…！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"흐음, 정말 사진만 찍으면 얌전히 돌아가 주겠나?","JPN":"ふむ。本当に写真だけ撮ったら何もせず帰ってくれるのか？","ENG":"Hmm, will you keep your promise if I let you take a selfie?","TWN":"咳咳，只要拍個照你就會乖乖回去嗎？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"그럼, 당연하지. 너한테도 나쁜 거래는 아닐걸.","JPN":"もちろん。そっちにとっても悪い取引じゃないっしょ。","ENG":"Of course. It will be good for you as well.","TWN":"我說話算話，而且你也沒有損失吧？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"내 팔로워들은 한두 명이 아니걸랑. 잘 풀리면 너도 인기 스타가 될 수 있다고.","JPN":"あたしはそこら辺の雑魚垢と違ってフォロワーの桁が違うからね。上手くいけば、お前も人気者になれるよ。","ENG":"I have a lot of followers. Taking a selfie with me might make you a superstar.","TWN":"我的粉絲很多欸，說不定你有機會爆紅喔！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"주인님! 저런 못된 유혹에 넘어가시면 안 됨다!","JPN":"ご主人様！　あんな誘惑に騙されてはいけないっす！","ENG":"Master! Don’t give in to that evil temptation!","TWN":"主人！你不要被迷惑！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"걱정 말게, 모네 양. 평화를 위해서라면 이 한 몸 기꺼이 바칠 수 있다네.","JPN":"心配は無用だ、モネ。平和のためならこの身を喜んで捧げる。","ENG":"Don’t worry, Mone. I’m willing to sacrifice for the great cause.","TWN":"莫妮，別擔心。只要能夠救大家，犧牲這副軀殼又算什麼。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"주인님……! 역시 멋지심다!","JPN":"ご主人様……！　やっぱりカッコいいっす！","ENG":"Master! You’re a saint, sir!","TWN":"主人…！果然很帥！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L24_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"……하아, 쌍으로 주책이군요.","JPN":"はあ……二人揃ってお笑いコンビでも組むつもりですか。","ENG":"... I can’t watch this.","TWN":"…哈，是在唱雙簧嗎？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"자, 이제 됐나?","JPN":"さあ、これでいいか？","ENG":"Are we done now?","TWN":"這樣可以了吧？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L29_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"우후후♪ 좋아, 생각지도 못하게 한 장 건졌네♬","JPN":"うふふ♪　いいよ。予想外の収穫♬","ENG":"Hmm. ♪ Yes, I didn’t expect it to be this good, actually. ♬","TWN":"呵呵呵♪ 很好，拍得比我想像中還好呢♬"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"약속대로 오늘은 물러나 줄게. 다음에 내가 오기 전까지 짐 싸 놓고 있으라고.","JPN":"約束どおり今日は帰ってやる。今度また来るからそれまでに荷物はちゃんとまとめておけよ。","ENG":"I’ll be going for today as I promised. But you’d better be gone when I come back.","TWN":"按照約定我今天就先離開，在我下次來之前，記得先把行李收拾好。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"아, 그리고 참.","JPN":"あ、そうだ。","ENG":"Oh, and one more thing.","TWN":"對了。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"다음엔 촌티 나는 말투로 떽떽거리지 마, 꼬맹이. 진심 들어 주기 괴롭거든.","JPN":"そのダサい喋り方で大声出すのはやめたほうがいいよ、チビ。ガチでウザすぎて聞いてられないわ。","ENG":"The way you talk is just so lame, kid. Such a pain in my ears.","TWN":"小鬼，你講話不要那麼多語助詞，聽得我很難受。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_TANK_MOVE"},{"id":"L36_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"그냥 나쁜 사람이 아니라 왕 나쁜 사람임다!","JPN":"普通の悪い人じゃなくて、めちゃくちゃ悪い人っす！","ENG":"You’re not just mean, but super evil mean!","TWN":"不是一般的壞人，是個大壞人唷！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_TANK_MOVE"}]`);export{e as default};